export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:10。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊圖書室旁的暗房。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門外地上放著兩支手機。一支是顧言的。一支是許星棠的。螢幕都朝下。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門關上之後，走廊的光只剩門縫底下那麼一條。暗房裡只有紅色安全燈——攝影組用的舊燈泡，瓦數很低，把所有東西染成暗琥珀色。沖洗槽乾了。架上全是過期的底片罐和積灰的鏡頭盒。天花板上那盞感應燈壞了很久，用膠帶貼住，不會亮。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）沒有監視器。這間暗房只有攝影組用，行政組不會管。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）手機留在外面。不寫進手機。只用紙。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠靠在沖洗槽旁邊。相機包沒有放下來——帶子還掛在肩上，她的手搭在包的翻蓋上，沒有鬆開。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她連在這裡都不放包。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）好。這樣才公平。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "上一輪——", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯「上一輪」。她不記得。但她已經接受了我知道不該知道的事。我不需要解釋怎麼知道的。我只需要告訴她這一輪要做什麼。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "上一輪我們抓林主任。抓到的是手，不是腦。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "這一輪，不抓人。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "測人。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "怎麼測。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "給不同的人不同的假情報。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "每個人只拿到一條。細節不一樣。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "然後看哪一條變成陷阱。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說話。但她的眼睛動了一下——從他的臉移到他口袋裡露出來的筆記本邊角，再移回來。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "幾條。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "三條。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "三條要能同時成立。不能互相打架。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "如果他們互相通氣，聽起來要像同一個慌亂計畫裡的不同備案。不是三個矛盾的故事。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "說。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從口袋裡抽出一張紙。攤在沖洗槽的乾槽上。紅燈把白紙染成暗橘色。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他寫。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一條。傳輸備案。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "如果直播線被切，鐘樓天線屋可能還接著舊廣播線。可以當最後備用傳輸點。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "這條給韓越。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二條。密碼備案。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "基座底板左側暗槽裡，可能有我爸留下的密碼提示。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "這條給林主任。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三條。暫存備案。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "如果我真的拿到相機，我會先藏在醫務室二號冰敷櫃。櫃門裡側貼一張紅色盤點標籤做記號。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "這條——", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的筆尖停在紙上。停了一秒。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "這條給邵警官。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暗房裡很安靜。紅燈不閃。水龍頭不滴。只有兩個人的呼吸。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "邵啟明。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她叫了全名。不是「邵叔」。不是「邵警官」。是全名。像在確認一個坐標。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "校慶安全負責人。你的緊急聯絡人。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你不想測他。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她看出來了。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我寫前兩條的時候沒有停。寫第三條的時候停了。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）一秒。她看見了那一秒。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "顧言。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "如果你要測人——", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "就連你自己最想相信的人也要測。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "否則這不是推理。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "是祈禱。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音沒有升高。沒有降低。每一個字都像放在桌上的棋子——落下去就不會再動。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不知道邵叔是誰。不知道他照顧了我七年。不知道他冬天會多帶一件外套來學校等我。不知道他每次問「吃了沒」的時候聲音會低半個音階，像怕吵醒什麼。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她只是在做一個調查者該做的事——最有權限的人，必須在名單上。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有錯。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我錯了。我在那一秒裡猶豫了。猶豫就是偏。偏了就不是測試。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯好。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把第三條寫完。筆尖在「邵」字上面壓出了一個墨點。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠低頭看那張紙。三條。三個名字。三組不一樣的細節。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "隔離。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "韓越只知道天線屋。林主任只聽到左側暗槽。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "完整知道醫務室二號冰敷櫃和紅色標籤的——", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "只有邵啟明。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "對。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這樣才公平。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她伸手把那張紙拿起來。看了看。然後——", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "撕。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從中間撕開。再對折。再撕。撕成四片。八片。十六片。手指很穩。每一撕的力道都一樣。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把碎片攏進掌心，走到角落的廢紙桶前，丟進去。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "紙不留。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "手機不帶進來。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "投放的時候只用面對面。不用訊息。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暗房裡又安靜了。紅燈把他們的影子拉得很長，貼在牆上，像兩個被壓扁的人。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三條假情報。三個名字。三組只有那個人才聽過的細節。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）哪一條變成陷阱，那一條的情報源就是能動全校安全權限的人。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯邵叔。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我寫了你的名字。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我沒有圈起來。但她在。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她替我圈了。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠走向門口。她沒有回頭。手搭上門把的時候，她停了一下。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "顧言。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你那張紙上，第三條的墨點比前兩條深。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "下次別犹豫。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拉開門。走廊的灰光灌進來，把紅色暗房劈成兩半。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她彎腰撿起自己的手機。走了。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在原地。看著廢紙桶裡那些碎片。紅燈下，白紙變成暗橘色的碎屑，像一窩被攪散的東西。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她說得對。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我寫第三條的時候，手在抖。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我不能抖。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輪，連我自己最想相信的人也要測。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）否則——", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是推理。是祈禱。", background: Background.Chapter_7_Ch7_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他彎腰撿起自己的手機。推開門。走廊上空蕩蕩的。雨還在下。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:25。", background: Background.Chapter_7_Ch7_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三條假情報已經在廢紙桶裡了。但在他的腦子裡，它們才剛開始。", background: Background.Chapter_7_Ch7_Act2_S0 },
];
